questionvariables.text:
/* Number of cows */
n : rand(6) + 12;

/* Milk production values (liters) */
data : makelist(rand(160)+200,i,1,n);

/* Class intervals */
c1_low : 200$
c1_high : 239$

c2_low : 240$
c2_high : 279$

c3_low : 280$
c3_high : 319$

c4_low : 320$
c4_high : 359$

/* Frequency calculations */
f1 : length(sublist(data,lambda([x], x>=c1_low and x<=c1_high)));
f2 : length(sublist(data,lambda([x], x>=c2_low and x<=c2_high)));
f3 : length(sublist(data,lambda([x], x>=c3_low and x<=c3_high)));
f4 : length(sublist(data,lambda([x], x>=c4_low and x<=c4_high)));
